    if (config != NULL_PTR)
    {
        mock_IfxGtm_Pwm_init_lastNumChannels = config->numChannels;
        mock_IfxGtm_Pwm_init_lastFrequency   = config->frequency;
    }
}

void IfxGtm_Pwm_updateChannelsDutyImmediate(IfxGtm_Pwm *pwm, float32 *requestDuty)
{
    (void)pwm;
    mock_IfxGtm_Pwm_updateChannelsDutyImmediate_callCount++;
    if (requestDuty != NULL_PTR)
    {
        uint32 n = mock_IfxGtm_Pwm_init_lastNumChannels ? mock_IfxGtm_Pwm_init_lastNumChannels : mock_IfxGtm_Pwm_initConfig_lastNumChannels;
        if (n > MOCK_MAX_CHANNELS) { n = MOCK_MAX_CHANNELS; }
        mock_IfxGtm_Pwm_updateChannelsDutyImmediate_lastNumChannels = n;
        if (n > 0)
        {
            memcpy(mock_IfxGtm_Pwm_updateChannelsDutyImmediate_lastDuties, requestDuty, n * sizeof(float32));
        }
    }
}

void IfxGtm_Pwm_interruptHandler(IfxGtm_Pwm_Channel *channel, void *data)
{
    (void)channel; (void)data;
    mock_IfxGtm_Pwm_interruptHandler_callCount++;
}

/* Reset all spies */
void mock_gtm_tom_3_phase_inverter_pwm_reset(void)
{
    mock_IfxGtm_Pwm_initConfig_callCount = 0;
    mock_IfxGtm_Pwm_initConfig_lastNumChannels = 0;
    mock_IfxGtm_Pwm_initConfig_lastFrequency = 0.0f;

    mock_IfxGtm_Pwm_init_callCount = 0;
    mock_IfxGtm_Pwm_init_lastNumChannels = 0;
    mock_IfxGtm_Pwm_init_lastFrequency = 0.0f;

    mock_IfxGtm_Pwm_updateChannelsDutyImmediate_callCount = 0;
    mock_IfxGtm_Pwm_updateChannelsDutyImmediate_lastNumChannels = 0;
    memset(mock_IfxGtm_Pwm_updateChannelsDutyImmediate_lastDuties, 0, sizeof(mock_IfxGtm_Pwm_updateChannelsDutyImmediate_lastDuties));

    mock_IfxGtm_Pwm_interruptHandler_callCount = 0;

    mock_IfxGtm_isEnabled_callCount = 0;
    mock_IfxGtm_isEnabled_returnValue = FALSE;

    mock_IfxGtm_enable_callCount = 0;

    mock_IfxGtm_Cmu_getModuleFrequency_callCount = 0;
    mock_IfxGtm_Cmu_getModuleFrequency_returnValue = 0.0f;

    mock_IfxGtm_Cmu_enableClocks_callCount = 0;

    mock_IfxPort_setPinModeOutput_callCount = 0;

    mock_togglePin_callCount = 0U;

    memset(mock_IfxGtm_Pwm_updateChannelsDeadTimeImmediate_lastDtRising, 0, sizeof(mock_IfxGtm_Pwm_updateChannelsDeadTimeImmediate_lastDtRising));
    memset(mock_IfxGtm_Pwm_updateChannelsDeadTimeImmediate_lastDtFalling, 0, sizeof(mock_IfxGtm_Pwm_updateChannelsDeadTimeImmediate_lastDtFalling));
}

